mapper.select:
		select count(distinct t.id)
		from wf_task t
		left join wf_order o on t.order_id = o.id
		left join wf_task_actor ta on ta.task_id=t.id
		left join wf_process p on p.id = o.process_id


                ta.actor_Id in

                    #{operator}



                and o.process_Id = #{request.processId}



				and p.display_Name like #{pattern} 


                and o.parent_Id = #{request.parentId}


                and t.order_id = #{request.orderId}


                and t.task_Name in

                    #{name}



                and t.task_Type = #{request.taskType}


                and t.perform_Type = #{request.performType}


                and t.create_Time >= #{request.createTimeStart}


                and t.create_Time <= #{request.createTimeEnd}

		select distinct o.process_Id, t.order_Id, t.id as id, t.id as task_Id, p.display_Name as process_Name, p.instance_Url, o.parent_Id, o.creator,
		o.create_Time as order_Create_Time, o.expire_Time as order_Expire_Time, o.order_No, o.variable as order_Variable,
		t.display_Name as task_Name, t.task_Name as task_Key, t.task_Type, t.perform_Type, t.operator, t.action_Url,
		t.create_Time as task_Create_Time, t.finish_Time as task_End_Time, t.expire_Time as task_Expire_Time, t.variable as task_Variable
		from wf_task t
		left join wf_order o on t.order_id = o.id
		left join wf_task_actor ta on ta.task_id=t.id
		left join wf_process p on p.id = o.process_id


                ta.actor_Id in

                    #{operator}



